import React from 'react';
import styled from 'styled-components';

const StyledButton = styled.button`
  background: ${props => props.outline ? 'transparent' : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'};
  color: ${props => props.outline ? '#667eea' : 'white'};
  padding: ${props => {
    if (props.small) return '8px 20px';
    if (props.large) return '14px 32px';
    return '12px 28px';
  }};
  border-radius: 40px;
  font-size: ${props => {
    if (props.small) return '0.8rem';
    if (props.large) return '1rem';
    return '0.9rem';
  }};
  font-weight: 600;
  transition: all 0.3s ease;
  width: ${props => props.fullWidth ? '100%' : 'auto'};
  border: ${props => props.outline ? '2px solid #667eea' : 'none'};
  cursor: pointer;

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 10px 15px -3px rgba(102, 126, 234, 0.3);
  }

  &:active {
    transform: translateY(0);
  }

  &:disabled {
    opacity: 0.6;
    cursor: not-allowed;
    transform: none;
  }
`;

export const Button = ({ children, ...props }) => {
  return <StyledButton {...props}>{children}</StyledButton>;
};
